import { useState } from "react";
import { Wallet, Plus, DollarSign, Ticket, Calendar, RefreshCw, CheckCircle, BarChart3, ScanLine, AlertCircle } from "lucide-react";
import { V } from "../utils/constants";
import { formatDate, shortAddr, soldPct } from "../utils/format";
import { useWallet } from "../context/WalletContext";
import { useApp } from "../context/AppContext";
import { withdrawOrganizerFunds } from "../utils/contract";
import ScanModal from "../components/ticket/ScanModal";
import { useNavigate } from "react-router-dom";

export default function DashboardPage() {
  const { wallet, connect, connecting } = useWallet();
  const { orgEvents, loadingEvents, refreshOrgEvents, refreshEvents } = useApp();
  const [showScan, setShowScan] = useState(false);
  const [wdBusy,   setWdBusy]  = useState(false);
  const [wdDone,   setWdDone]  = useState(false);
  const [wdErr,    setWdErr]   = useState("");
  const navigate = useNavigate();

  const totRev = orgEvents.reduce((a,e) => a + parseFloat(e.ticketPrice||0)*e.soldTickets, 0);
  const totTix = orgEvents.reduce((a,e) => a + e.soldTickets, 0);

  const doWithdraw = async () => {
    setWdBusy(true); setWdErr("");
    try {
      await withdrawOrganizerFunds();
      setWdDone(true);
    } catch(err) {
      setWdErr(err?.reason || err?.message || "Withdrawal failed.");
    } finally { setWdBusy(false); }
  };

  const doRefresh = async () => {
    await Promise.all([refreshOrgEvents(wallet), refreshEvents()]);
  };

  if (!wallet) return (
    <div style={{padding:"80px 24px",display:"flex",alignItems:"center",justifyContent:"center",minHeight:"80vh"}}>
      <div style={{textAlign:"center",maxWidth:380}}>
        <div style={{width:70,height:70,borderRadius:20,background:V.b50,border:"1px solid "+V.b100,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 18px"}}>
          <BarChart3 size={30} color={V.brand}/>
        </div>
        <h2 style={{fontFamily:"Outfit",fontWeight:900,fontSize:25,marginBottom:10,color:V.text}}>Organizer Dashboard</h2>
        <p style={{color:V.muted,marginBottom:24,lineHeight:1.7,fontSize:14}}>
          Connect your wallet to manage your events and withdraw revenue.
        </p>
        <button className="bp" onClick={connect} disabled={connecting} style={{borderRadius:14,padding:"13px 28px",fontSize:14,gap:10}}>
          {connecting ? <><RefreshCw size={14} className="spin"/>Connecting…</> : <><Wallet size={15}/>Connect Wallet</>}
        </button>
      </div>
    </div>
  );

  return (
    <div style={{padding:"80px 24px 80px",maxWidth:920,margin:"0 auto"}}>
      {showScan && <ScanModal events={orgEvents} onClose={()=>setShowScan(false)}/>}

      <div className="fu" style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:26,flexWrap:"wrap",gap:12}}>
        <div>
          <h1 style={{fontFamily:"Outfit",fontWeight:900,fontSize:30,color:V.text,marginBottom:4}}>Dashboard</h1>
          <div style={{fontSize:13,color:V.muted,fontFamily:"monospace"}}>{wallet}</div>
        </div>
        <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
          <button className="bg" onClick={doRefresh} style={{gap:6,color:V.muted,fontSize:13,borderRadius:11}}>
            <RefreshCw size={13} className={loadingEvents?"spin":""}/>Refresh
          </button>
          <button className="bs" onClick={() => navigate("/create")} style={{gap:6,borderRadius:12}}><Plus size={14}/>Host Event</button>
          <button className="bs" onClick={()=>setShowScan(true)} style={{gap:6,borderRadius:12}}><ScanLine size={14}/>Scan Tickets</button>
          <button className="bp" onClick={doWithdraw} disabled={wdBusy||wdDone||orgEvents.length===0}
            style={{gap:6,borderRadius:12,opacity:(wdDone||orgEvents.length===0)?.65:1}}>
            {wdBusy ? <><RefreshCw size={14} className="spin"/>Withdrawing…</> :
             wdDone ? <><CheckCircle size={14}/>Withdrawn</> :
             <><DollarSign size={14}/>Withdraw Funds</>}
          </button>
        </div>
      </div>

      {wdErr && (
        <div style={{background:"#FEF2F2",border:"1px solid #FCA5A5",borderRadius:12,padding:"11px 14px",marginBottom:18,display:"flex",gap:9,fontSize:13,color:"#DC2626"}}>
          <AlertCircle size={14} style={{flexShrink:0,marginTop:1}}/>{wdErr}
        </div>
      )}

      {/* Stat cards */}
      <div className="fu2" style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:16,marginBottom:26}}>
        {[
          {l:"Revenue (OG)",   v:totRev.toFixed(4)+" OG", sub:"from tickets",   I:DollarSign, c:V.brand},
          {l:"Tickets Sold",   v:totTix.toLocaleString(), sub:"all events",      I:Ticket,     c:"#16A34A"},
          {l:"Events Hosted",  v:orgEvents.length,         sub:"on 0G chain",    I:Calendar,   c:"#D97706"},
        ].map(({l,v,sub,I,c})=>(
          <div key={l} className="sc">
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
              <span style={{fontSize:12,color:V.muted,fontFamily:"Outfit",fontWeight:600}}>{l}</span>
              <div style={{width:34,height:34,borderRadius:9,background:c+"18",display:"flex",alignItems:"center",justifyContent:"center"}}>
                <I size={16} color={c}/>
              </div>
            </div>
            <div style={{fontFamily:"Outfit",fontWeight:900,fontSize:24,color:c}}>{v}</div>
            <div style={{fontSize:12,color:V.mutedL,marginTop:3}}>{sub}</div>
          </div>
        ))}
      </div>

      {/* Event table */}
      <div className="fu3 card" style={{overflow:"hidden"}}>
        <div style={{padding:"17px 22px",borderBottom:"1px solid "+V.borderS,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <h3 style={{fontFamily:"Outfit",fontWeight:700,fontSize:16,color:V.text}}>Your Events</h3>
          <span className="bdg bdg-p">{orgEvents.length} event{orgEvents.length!==1?"s":""}</span>
        </div>

        {loadingEvents ? (
          <div style={{padding:"32px 22px",textAlign:"center"}}>
            <div style={{width:28,height:28,borderRadius:"50%",border:"3px solid "+V.b100,borderTopColor:V.brand,margin:"0 auto",animation:"spinA 1s linear infinite"}}/>
          </div>
        ) : orgEvents.length===0 ? (
          <div style={{padding:"32px 22px",textAlign:"center",color:V.muted,fontSize:14}}>
            No events yet.{" "}
            <button className="bg" onClick={() => navigate("/create")} style={{color:V.brand,fontWeight:600}}>
              Host your first event →
            </button>
          </div>
        ) : orgEvents.map((ev,i)=>{
          const pct = soldPct(ev.soldTickets,ev.maxTickets);
          const rev = (parseFloat(ev.ticketPrice||0)*ev.soldTickets).toFixed(4);
          return (
            <div key={ev.id} style={{padding:"17px 22px",borderBottom:i<orgEvents.length-1?"1px solid "+V.borderS:"none",display:"flex",gap:14,alignItems:"center",transition:"background .15s",cursor:"default"}}
              onMouseEnter={e=>e.currentTarget.style.background=V.surface}
              onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
              <div style={{width:44,height:44,borderRadius:12,background:ev.bg,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>
                {ev.emoji}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontFamily:"Outfit",fontWeight:700,fontSize:14,color:V.text,marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{ev.name}</div>
                <div style={{fontSize:12,color:V.muted,marginBottom:7}}>{formatDate(ev.startTime)} · {[ev.city,ev.country].filter(Boolean).join(", ") || "Location TBD"}</div>
                <div style={{display:"flex",alignItems:"center",gap:8}}>
                  <div className="pb" style={{height:3,flex:1}}><div className="pf" style={{width:pct+"%"}}/></div>
                  <span style={{fontSize:11,color:V.mutedL,flexShrink:0}}>{pct}%</span>
                </div>
              </div>
              <div style={{textAlign:"right",flexShrink:0}}>
                <div style={{fontFamily:"Outfit",fontWeight:800,fontSize:16,color:V.text}}>{rev} OG</div>
                <div style={{fontSize:12,color:V.muted,marginTop:2}}>{ev.soldTickets.toLocaleString()} tickets</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
